internal fun reduceExpenseApprovalLogic(state: ExpenseApprovalLogicState, event: ReducerEvent): ExpenseApprovalLogicState =
    when (event) {
        is ReducerEvent.Public -> when (val e = event.event as ExpenseApprovalLogicEvent) {
            is ExpenseApprovalLogicEvent.OnFieldEdit -> {
                val slot = state.formFields[e.portId]
                    ?: FormFieldsSlot(values = emptyMap())
