            is ExpenseApprovalLogicEvent.OnEmit -> state // side-effecting; handled in ViewModel.handleEmit
        }
        is ReducerEvent.SinkArrival -> {
            state.copy(
                latestIps = state.latestIps + (event.portId to LatestIpSlot(ip = event.ip)),
            )
        }
